Here's a complete example:

### XAML — `ItemsPage.xaml`

```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             xmlns:models="clr-namespace:MyApp.Models"
             xmlns:vm="clr-namespace:MyApp.ViewModels"
             x:Class="MyApp.Views.ItemsPage"
             x:DataType="vm:ItemsViewModel">

    <RefreshView IsRefreshing="{Binding IsRefreshing}"
                 Command="{Binding RefreshCommand}">
        <CollectionView ItemsSource="{Binding Items}"
                        SelectionMode="Single"
                        SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                        SelectionChangedCommand="{Binding ItemSelectedCommand}">
            <CollectionView.ItemTemplate>
                <DataTemplate x:DataType="models:Item">
                    <Grid Padding="12" ColumnDefinitions="48,*" ColumnSpacing="12">
                        <Image Source="{Binding Icon}"
                               WidthRequest="40" HeightRequest="40" />
                        <VerticalStackLayout Grid.Column="1" VerticalOptions="Center">
                            <Label Text="{Binding Name}" FontAttributes="Bold" />
                            <Label Text="{Binding Description}"
                                   FontSize="12" TextColor="Gray" />
                        </VerticalStackLayout>
                    </Grid>
                </DataTemplate>
            </CollectionView.ItemTemplate>
            <CollectionView.EmptyView>
                <ContentView>
                    <Label Text="No items found."
                           HorizontalOptions="Center" VerticalOptions="Center" />
                </ContentView>
            </CollectionView.EmptyView>
        </CollectionView>
    </RefreshView>
</ContentPage>
```

### ViewModel — `ItemsViewModel.cs`

```csharp
using CommunityToolkit.Mvvm.ComponentModel;
using CommunityToolkit.Mvvm.Input;
using System.Collections.ObjectModel;

public partial class ItemsViewModel : ObservableObject
{
    private readonly IItemService _itemService;

    public ObservableCollection<Item> Items { get; } = new();

    [ObservableProperty]
    private Item? _currentItem;

    [ObservableProperty]
    private bool _isRefreshing;

    public ItemsViewModel(IItemService itemService)
    {
        _itemService = itemService;
    }

    [RelayCommand]
    private async Task ItemSelected()
    {
        if (CurrentItem is null) return;

        await Shell.Current.GoToAsync(
            $"{nameof(DetailPage)}?id={CurrentItem.Id}");

        // Clear selection so the user can re-select the same item later
        CurrentItem = null;
    }

    [RelayCommand]
    private async Task Refresh()
    {
        try
        {
            var data = await _itemService.GetItemsAsync();
            Items.Clear();
            foreach (var item in data)
                Items.Add(item);
        }
        finally
        {
            IsRefreshing = false;   // Must set false to hide the spinner
        }
    }
}
```

### Key bindings explained

| XAML Property | ViewModel Property | Why |
|---|---|---|
| `ItemsSource="{Binding Items}"` | `ObservableCollection<Item>` | Auto-updates UI on add/remove |
| `SelectedItem="{Binding CurrentItem, Mode=TwoWay}"` | `Item? CurrentItem` | Tracks the tapped item |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires on tap → navigates to detail |
| `RefreshView.IsRefreshing` | `bool IsRefreshing` | Controls the spinner; **set `false` when done** |
| `RefreshView.Command` | `RefreshCommand` | Triggers API reload on pull |

### Important details

- **`x:DataType`** is set on both the page (ViewModel) and the `DataTemplate` (Model) for compiled bindings.
- **Clear `CurrentItem`** after navigation — otherwise tapping the same item again won't fire `SelectionChangedCommand`.
- **Always set `IsRefreshing = false`** in a `finally` block so the spinner disappears even if the API call fails.
- Use **`ObservableCollection<T>`**, not `List<T>` — swapping a `List` forces a full re-render.
- Register the detail page route in `AppShell.xaml.cs`:
  ```csharp
  Routing.RegisterRoute(nameof(DetailPage), typeof(DetailPage));
  ```
